const normalizeKimiKey = (value?: string) => String(value || '')
  .trim()
  .toLowerCase()
  .normalize('NFKD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/&/g, ' and ')
  .replace(/[^a-z0-9\u4e00-\u9fff]+/g, '-')
  .replace(/^-+|-+$/g, '');

const TEAM_BY_KEY = new Map<string, KimiWorldCupTeamProfile>();
KIMI_WORLD_CUP_DATASET.teams.forEach((team) => {
  const profile = team as KimiWorldCupTeamProfile;
  [profile.key, profile.nameZh, profile.nameEn].forEach((value) => TEAM_BY_KEY.set(normalizeKimiKey(value), profile));
});

export const getKimiWorldCupTeamProfile = (value?: string): KimiWorldCupTeamProfile | null => {
  const key = normalizeKimiKey(value);
  return TEAM_BY_KEY.get(key) || null;
};

export const getKimiWorldCupFixtureSeeds = (): KimiWorldCupFixtureSeed[] => (
  KIMI_WORLD_CUP_DATASET.fixtures as unknown as KimiWorldCupFixtureSeed[]
);
